INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$00ad0f17-2cd6-423c-8035-9139d0b402ab$tag$, $tag$2026011600164$tag$, $tag$Orlando Oliveira (5592994236893)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Novo Testamento","time":"16/01/2026 16:18:33"},{"role":"client","text":"🌟 Boa tarde Orlando Oliveira! Que alegria ter você aqui com a gente! 🙌","time":"16/01/2026 16:18:34"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"16/01/2026 16:18:37"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"16/01/2026 16:18:42"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"16/01/2026 16:18:49"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"16/01/2026 16:19:11"},{"role":"client","text":"Olá! Orlando Oliveira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"16/01/2026 16:19:11"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"16/01/2026 16:19:15"},{"role":"client","text":"Saber sobre os cursos","time":"16/01/2026 16:19:26"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"16/01/2026 16:19:30"},{"role":"client","text":"Pós-Graduação","time":"16/01/2026 16:19:43"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"16/01/2026 16:19:48"},{"role":"client","text":"Novo Testamento","time":"16/01/2026 16:20:02"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"16/01/2026 16:20:03"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"16/01/2026 16:20:07"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"16/01/2026 16:20:37"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"16/01/2026 16:20:38"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"16/01/2026 16:23:00"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"16/01/2026 16:23:13","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"16/01/2026 16:23:39","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\n﻿Teologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações. ","time":"16/01/2026 16:23:58","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026. \n\n🎁 Cupom de Desconto Novo Testamento: *BOLSA50*\n\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_23\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"16/01/2026 16:24:06","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Atendimento Finalizado!\n\nOrlando Oliveira, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/01/2026 08:11:01"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"19/01/2026 08:11:02"},{"role":"client","text":"Orlando Oliveira, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"19/01/2026 08:26:03"}]$tag$, $tag$2026-01-16 16:18:33+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 10, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$01889640-92da-4adf-9746-7ccee131a0e6$tag$, $tag$2026011600165$tag$, $tag$Matheus Fernandes (5586995589478)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"16/01/2026 16:33:09"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"16/01/2026 16:33:10"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"16/01/2026 16:35:33"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"16/01/2026 16:38:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"16/01/2026 16:38:25","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Boa tarde, Karina! Ótimas condições. Eu fiquei sabendo dessa faculdade pelo meu pastor.","time":"16/01/2026 16:41:20"},{"role":"client","text":"Estou conhecendo agora.","time":"16/01/2026 16:41:28"},{"role":"client","text":"Antes de prosseguir, eu gostaria de tirar uma dúvida.","time":"16/01/2026 16:41:46"},{"role":"client","text":"Eu cursei 2 anos no Seminário Teológico Batista de Teresina o curso de Formação Pastoral e agora iria para o terceiro ano. Só que estou cogitando a possibilidade de mudar de instituição. Seria possível eu reaproveitar algumas matérias que paguei?","time":"16/01/2026 16:43:36"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"16/01/2026 16:45:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Fechando hoje, eu consigo 20% de desconto!","time":"16/01/2026 16:45:50","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"16/01/2026 16:46:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Reconhecido pelo MEC?","time":"16/01/2026 16:46:29","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Infelizmente não","time":"16/01/2026 16:47:11"},{"role":"agent","text":"*Karina Pimentel:* Certo!","time":"16/01/2026 16:48:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Para ocorrer o aproveitamento, teria de ser reconhecido!","time":"16/01/2026 16:49:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi.","time":"16/01/2026 16:49:55"},{"role":"client","text":"As aulas são todos os dias?","time":"16/01/2026 16:50:00"},{"role":"client","text":"Ah, mais uma coisa, quantas disciplinas tem o curso? E quantas posso cursar por mês?","time":"16/01/2026 16:57:14"},{"role":"agent","text":"*Karina Pimentel:*  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"16/01/2026 17:01:50","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nMatheus Fernandes, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/01/2026 10:22:38"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"19/01/2026 16:55:15"},{"role":"client","text":"Sua sessão expirou!","time":"19/01/2026 16:57:17"}]$tag$, $tag$2026-01-16 16:33:09+00$tag$, FALSE, FALSE, 7.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 10, 2, 9, 9, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$b82b72b2-7adf-4e7c-92b7-fefd6e680731$tag$, $tag$2026011600173$tag$, $tag$Andre Luiz 🏳️ (5511988000490)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"16/01/2026 17:33:36"},{"role":"client","text":"🌟 Boa tarde Andre Luiz 🏳️! Que alegria ter você aqui com a gente! 🙌","time":"16/01/2026 17:33:37"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"16/01/2026 17:33:40"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"16/01/2026 17:33:44"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"16/01/2026 17:33:48"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"16/01/2026 17:33:54"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"16/01/2026 17:34:01"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"16/01/2026 17:34:02"},{"role":"client","text":"Sim, concordo","time":"16/01/2026 17:34:11"},{"role":"client","text":"✅ Obrigado, Andre Luiz 🏳️! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"16/01/2026 17:34:13"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"16/01/2026 17:34:17"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"16/01/2026 17:34:32"},{"role":"client","text":"Olá! Andre Luiz 🏳️!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"16/01/2026 17:34:34"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"16/01/2026 17:34:37"},{"role":"client","text":"Saber sobre os cursos","time":"16/01/2026 17:34:49"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"16/01/2026 17:34:53"},{"role":"client","text":"Pós-Graduação","time":"16/01/2026 17:35:04"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"16/01/2026 17:35:08"},{"role":"client","text":"Psicoteologia","time":"16/01/2026 17:35:25"},{"role":"client","text":"Integra áreas do cuidado integral com a Teologia para compreender o ser humano de maneira profunda.\n 🧠 Corpo, mente e espírito.\n 📚 Forma profissionais preparados para oferecer cuidado emocional e espiritual com profundidade acadêmica e sensibilidade cristã.\n📌 Voltado para profissionais da área da saúde, teologia, aconselhamento, capelania e interessados na temática.\n🎓 Professores mestres e doutores na área.\n\n💻 Estudo online (100% EAD) e contextualizado\n","time":"16/01/2026 17:35:28"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"16/01/2026 17:35:32"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"16/01/2026 17:35:44"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"16/01/2026 17:35:45"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"16/01/2026 17:36:18"},{"role":"agent","text":"*Karina Pimentel:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"16/01/2026 17:36:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Fevereiro 2026!","time":"16/01/2026 17:37:04","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Olá Karina","time":"16/01/2026 17:37:18"},{"role":"client","text":"Legal, quais são os valores?","time":"16/01/2026 17:37:37"},{"role":"client","text":"Tem a ementa do curso para eu ver?","time":"16/01/2026 17:37:56"},{"role":"client","text":"Uau... tá bem caro \nNão tem bolsa de estudos? \nEsse valor eu pago numa pós de neuropsicologia na PUC-PR 😮","time":"16/01/2026 17:38:55"},{"role":"agent","text":"*Karina Pimentel:* \n *Ementa da Pós de Psicoteologia*\n\n-Introdução à Psicoteologia\nDr. Sérgio Queiroz 80 horas\nEmenta:\nAnálise introdutória da Psicoteologia como campo interdisciplinar, que\nintegra a reflexão filosófica e teológica das grandes tradições cristãs à\ninvestigação científica e ao cuidado da psique humana. Estudo de suas\norigens históricas, fundamentos bíblico-teológicos, pressupostos filosóficos\ne consolidação contemporânea como proposta acadêmica emergente.\nDiscussão dos principais modelos de integração entre Teologia e\nteorias/práticas terapêuticas, de acordo com as contribuições de Eric\nJohnson, Paul Moes, Donald Riek e Malcolm Jeeves. Visão panorâmica dos\nfundamentos teológicas e terapêuticos das psicoteologias Ortodoxa, Católica\ne Reformada. Análise preliminar de algumas das principais abordagens\npsicoterapicas contemporâneas à luz da antropologia cristã e possíveis\ninterações com a Teologia Cristã. O dilema mente-cérebro. Quadro\ncontemporâneo das pesquisas em Psicoteologia nas contribuições de Harold\nKoenig e outros cientistas.\n\n\n-Introdução à Cosmovisão e Filosofia cristã\nDr. Bruno Ribeiro 40 horas\nEmenta: Compreensão do conceito de cosmovisão cristã, seus principais\nautores e suas implicações para a reflexão filosófica e para os diversos\ncampos do saber. Entendimento das características fundamentais da\ncosmovisão cristã, ancorando-se na narrativa Criação-Queda-Redenção.\nExploração das ferramentas teóricas para que o aluno analise e confronte\ndiferentes cosmovisões a partir de um compromisso fundante com a\ncosmovisão cristã. Análise da cosmovisão do Self e da construção da\nidentidade em Charles Taylor e em Carl Trueman. Reflexão sobre os\nfundamentos bíblicos da identidade humana, contrastando-os com as\nconcepções contemporâneas do Self. Os temas abordados serão: Conceito\nde cosmovisão; Propósito Divino para a Criação e Identidade Humana;\nVisão contemporanea do Self; Problemas com a visão contemporânea do\nSelf; Visão Cristã do Self.\n\n\n-Fundamentos Históricos e Filosóficos da Psicoteologia\nDr. Josemar Bandeira 40 horas\nEmenta: Introdução à Psicoteologia: Definição, objeto de estudo e\ninterdisciplinaridade. Raízes Filosóficas da Psicoteologia: o dualismo\nplatônico e o hilemorfismo aristotélico. O pensamento estoico e a alma como\nparte da ordem cósmica. Psicoteologia na Idade Média: o Santo Agostinho:\nintrospecção, graça divina e livre-arbítrio. O Tomás de Aquino: fé, razão e a\nalma como forma substancial. Transição para a Modernidade: O impacto do\ndualismo cartesiano: mente, corpo e alma. Kant e a moralidade como ponte\nentre teologia e psicologia. Aspectos da alma e Espiritualidade no Século\nXX: Freud e a crítica à religião. Jung e os arquétipos do inconsciente coletivo.\nViktor Frankl e a busca por sentido na logoterapia. Movimentos\nContemporâneos: transpessoal e positiva: Maslow, Wilber e a espiritualidade\nna ciência. O diálogo inter-religioso e a psicoteologia em uma sociedade\npluralista. Desafios e Perspectivas da Psicoteologia no Século XXI:\nEspiritualidade e saúde mental: um campo em expansão. A psicoteologia no\naconselhamento pastoral.\n\n\n-Psicoteologia Cristã Ortodoxa\nDr. Sérgio Queiroz 40 horas\nEmenta: (Em finalização!)\n\n\n-Correntes Contemporâneas das Psicoterapias\nMs. Fabiana Nascimento\nDra. Rebecca Athayde\n42 horas\nEmenta: Neste componente curricular o passeio se dará pela história dos\nconhecimentos da processos mentais fazendo um retorno à longa tradição\nda história dos saberes e das ideias que antecede o marco contemporâneo\nem 1879. Dessa forma, após distinguir correntes das escolas da\npsicoterapias serão apresentadas as cinco correntes fundamentais a partir\nde um pensamento tomista. Os temas abordados serão: Apresentar a\nhistória da dos processos cognitivos a partir da autoridade da história dos\nsaberes e das ideias. Descontruir o princípio norteador desta corrente de que\no inconsciente governa uma pessoa. Resgatar fundamentos de\nresponsabilidade e da pessoa humana racional constituídos por Rudolf\nAllers, desviados pela ética libertária do humanismo. Discutir o cientificismo\npróprio do condutismo e mais uma vez a ética libertária do humanismo.\nAlertar sobre esta corrente como uma alternativa ao condutismo e à\npsicanálise como recurso de fundamento libertário de opressões exteriores\npara dessa forma decidir seguindo seus impulsos. Nesta corrente, o homem\né deus. Interpretar como os elementos cognitivos se tornaram tema central\nde estudos parafraseando a mente humana a um processador de\ninformações conforme computador.\nAula adicional sobre “O estudo dos temperamentos na psicoterapia”.\n\n\n-Psicoterapia Tomista I – Introdução à Psicoterapia Tomista,\nEmoções e paixões\nDr. Andrei Alves\nDr. Vítor Meireles\n40 horas\nEmenta: O que é Psicoterapia Tomista?; Diferença entre as psicoterapias;\nPsicoterapias contemporâneas e ausência de base metafísica; Introdução à\nalma: essência e potências; Potências da alma: intelecto e vontade; Apetite\nsensitivo e afetividade; Domínio racional vs. domínio emocional; As paixões\ne sua moralidade; O fim último do homem e a busca da felicidade; Felicidade\npara São Tomás vs. felicidade; Integração das paixões e ordenamento da\nalma; Virtudes como caminho para a saúde psíquica; A tristeza como \"dor da\nalma\"; A tristeza que santifica; Sofrimento e a presença de Deus; A\nconsolação e o amor como restauradores psíquicos; Princípios fundamentais\nda Psicoterapia Tomista; A prudência e a autorresponsabilidade; Relação\nterapêutica e o papel do psicoterapeuta; A graça e sua influência na\npsicoterapia.\n\n\n-Psicoterapia Tomista II – Psicopatologias da alma e formação da\npersonalidade\nDr. Andrei Alves\nMs. Daniel Ouriques\n42 horas\nEmenta: O que são enfermidades da alma?; Diferença entre doenças da\nalma e doenças do corpo; O vício humano como enfermidade psíquica;\nPersonalidade viciosa e desordem da alma; Egoísmo, egocentrismo e\nnarcisismo; Amor desordenado de si mesmo; Soberba e inveja como\npatologias da alma; Preguiça e tristeza como obstáculos ao crescimento\nhumano; Medo e agressividade; Avareza e apego desordenado; Ansiedade\ne depressão sob a ótica tomista; Relação entre vícios e transtornos\ncontemporâneos; Virtudes como caminho de cura; Virtude da temperança e\no equilíbrio das paixões; Prudência e fortaleza na formação da\npersonalidade; Ordenamento afetivo e espiritual; Princípios de uma\npsicoterapia baseada em virtudes; O papel do terapeuta na formação da\npersonalidade; Educação das paixões como método terapêutico; A graça e\na restauração da alma.\nAula adicional sobre “construção de uma personalidade forte.”\n\n\n-Introdução a ciência da felicidade\nMs. Alessandra Magalhães Cavalcanti 40 horas\nEmenta: Explorar os princípios da ciência do bem-estar, Positiva ou também\nda Felicidade, e sua interface com a Psicoteologia, promovendo uma24\ncompreensão integrada sobre o bem-estar, as virtudes e a espiritualidade.\nSerão abordados os temas: Conceito e histórico. Psicoteologia: interface na\npromoção do bem-estar. Sentido e propósito de vida: integração entre fé,\nvalores e a teoria do bem-estar PERMA de Seligman e da Teoria do Fluxo\n(Flow), de Csikszentmihalyi. Virtudes, Forças de Caráter e Propósito de Vida.\nClassificação VIA (Character Strengths) das virtudes e forças de caráter.\nDesenvolvimento das forças e virtudes no cotidiano. O sentido da vida.\nEmoções Positivas, resiliência e espiritualidade. O papel da fé nas emoções\npositivas e na saúde mental. O papel da espiritualidade no fortalecimento da\nresiliência e na superação de crises. Exercícios de gratidão, otimismo e\nreestruturação cognitiva positiva. Práticas baseadas em gratidão, perdão e\ncompaixão. Meditação, oração e mindfulness como práticas de\nautotransformação. Prática e Reflexão final.\n\n\n-Terapia Cognitivo-Comportamental em Psicoteologia\nDr. Cyntia Diógenes Ferreira de Moraes\nMs. Alessandra Magalhães\nEsp. Juliana Araújo\n44 horas\nEmenta:A disciplina apresenta uma introdução a teoria, princípios e habilidades\nessenciais da terapia cognitivo-comportamental (TCC), bem como a\nadaptação dos protocolos de TCC baseada nos protocolos desenvolvidos\npela Duke University. Portanto, para abarcar os conteúdos propostos pela\ndisciplina foram divididos em dois grupos: “Antes de mudar é preciso\nconhecer” e “é preciso mudar”.\nAula adicional sobre “Comunicação não-violenta” e “Psicoterapia com\ncrianças e a Psicoteologia”\n\n\n-Logoterapia: sentido da vida e Psicoteologia\nDr. Alisson de Meneses Pontes 40 horas\nEmenta: Vida e obra de Viktor Frankl. Pressupostos básicos da Logoterapia\ne Análise Existencial: Liberdade da vontade, Vontade de sentido, Sentido da\nvida e Ontologia dimensional. Visão de homem e de mundo da LAE.\nAplicações práticas da LAE. Logoterapia e Psicoteologia.\n\n\n-Neurociências, psicoterapia do trauma e fé cristã\nEsp. Aender Borba\nEsp. Ramon Medeiros\n42 horas\nEmenta: A ementa desta disciplina pretende oferecer uma abordaegem\nintegral do ser humano. As aulas seguirão três eixos norteadores: 1.\nCompreensão da dimensão biológica: corporeidade e cérebro; com os\nseguintes subtemas: funcionamento do cérebro e sistemas neurobiológicos;\nneuroplasticidade e recuperação de traumas; interação entre corpo e\nmente. 2. Compreensão da dimensão psicológica: impacto do viver;\nque abordará os subtemas: definição e tipos de trauma psicológico;\nTranstorno de Estresse Pós-Traumático (TEPT) e suas manifestações;\ntécnicas de psicoterapia para tratamento de traumas. 3. Compreensão da\ndimesão espiritual e a resposta cristã: com os subtemas: conceitos de\nespiritualidade e religiosidade cristã; fé e espiritualidade na recuperação de\ntraumas, integração de práticas espirituais na psicoterapia.\nAula adicional sobre “EMDR e Psicoteologia: reflexões a partir da\ncosmovisão cristã.” \n\n\n-Psicoteologia do Aconselhamento Bíblico\nDr. Saulo Ribeiro\nMs. Gabriela Rique\n42 horas\nEmenta: A disciplina apresenta uma introdução ao aconselhamento cristão\ne sua importância a partir de ferramentas da Teologia para práticas e\nabordagens neste modelo de aconselhamento. Serão apresentadas algumas\ndiferenças entre aconselhamento secular e cristão e fundamentos bíblicos\ndo aconselhamento tendo a Escritura Sagrada como alicerce. Entre outros\ntemas, serão abordadas a compreensão do sofrimento, pecado e\nadoecimento mental; resolução de conflitos e arrependimento; vícios\nhumanos e questões éticas no aconselhamento cristão; limites e\nresponsabilidades do conselheiro: postura e conduta, questões de\nconfidencialidade e consentimento; cuidado pastoral e aconselhamento. Os\ntemas abordados serão: Visão bíblica da natureza e do estado da\nhumanidade, a responsabilidade humana e “o problema do mal”; Conceito e\nnecessidade de aconselhamento; Aconselhamento a partir das Escrituras.\nAnsiedade, solidão, depressão, ira, culpa, problemas conjugais e de\nsolteiros, desenvolvimento familiar e crises interiores. Sexualidade,\nautoestima, “adultização” infantil e imaturidade, vícios, traumas, lutos e crises\nsociais. A Prática e o processo de aconselhamento cristão; as lógicas do\naconselhamento bíblico: amor, empatia, a ajuda ao outro. Graça e virtude: o\nque Deus nos chama a fazer? A importância de conhecer as virtudes\nhumanas e seus vícios contrários; quem é e como deve viver o conselheiro:\na necessidade de se proteger. A Trindade como principal elemento da vida\nequilibrada para frutificação.\nAula adicional sobre “Psiquiatria e Psicoteologia”.\n\n\n-Metodologia da pesquisa em Psicoteologia\nMs. Raphael Falcão 40 horas\nEmenta: Pressupostos filosóficos para a pesquisa científica. Sistematização\ne elaboração do projeto de pesquisa. Ética na pesquisa e na publicação\ncientífica. Temas pertinentes à Psicoteologia. Classificações e tipos de\npesquisa. Interpretação de estudos científicos e hierarquia de evidências.\nMétodos de coleta e análise de dados. Roteiro prático para projeto de\npesquisa. Processo de publicação da pesquisa.","time":"16/01/2026 17:39:00","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Fechando hoje eu consigo um desconto especial de 50%.","time":"16/01/2026 17:39:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Todos os meses?","time":"16/01/2026 17:39:42"},{"role":"agent","text":"*Karina Pimentel:* Mensalidades ficarão no valor de R$ 243,50.","time":"16/01/2026 17:39:45","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vamos garantir a sua vaga?","time":"16/01/2026 17:47:14","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Ainda tá caro... qual o melhor que você consegue?","time":"16/01/2026 18:08:23"},{"role":"client","text":"E você ainda não me passou a ementa 🙂","time":"16/01/2026 18:51:28"},{"role":"agent","text":"*Karina Pimentel:* Oi, pode falar agora?","time":"19/01/2026 08:11:32","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Olá, sim, por aqui","time":"19/01/2026 08:12:48"},{"role":"agent","text":"*Karina Pimentel:* Tudo bem, Sr André?","time":"19/01/2026 09:12:13","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Mandei acima!","time":"19/01/2026 09:12:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Tudo bem Karina graças a Deus e você?","time":"19/01/2026 10:45:19"},{"role":"client","text":"Acho que não... não tem as disciplinas que serão estudadas","time":"19/01/2026 10:45:36"},{"role":"agent","text":"*Karina Pimentel:* Módulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão","time":"19/01/2026 10:57:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Certo, parece legal","time":"19/01/2026 11:25:18"},{"role":"client","text":"E quanto aos valores?","time":"19/01/2026 11:25:22"},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Fevereiro 2026!","time":"19/01/2026 11:27:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 50% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 243,50.\nVamos garantir a sua vaga? 😊","time":"19/01/2026 11:28:18","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Poxa, ainda é um valor alto para eu pagar","time":"19/01/2026 12:13:05"},{"role":"agent","text":"*Karina Pimentel:* Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"19/01/2026 20:36:42","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nAndre Luiz 🏳️, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/01/2026 20:36:44"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"19/01/2026 20:36:45"},{"role":"client","text":"2","time":"19/01/2026 20:41:59"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"19/01/2026 20:41:59"},{"role":"client","text":"1","time":"19/01/2026 20:42:09"},{"role":"client","text":"Digite em uma linha o seu comentario sobre o atendimento:","time":"19/01/2026 20:42:10"},{"role":"client","text":"Não houve negociação. Só script pronto. Se a pré venda é assim, imagine o suporte ao aluno.","time":"19/01/2026 20:42:42"},{"role":"client","text":"Andre Luiz 🏳️, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"19/01/2026 20:42:43"}]$tag$, $tag$2026-01-16 17:33:36+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 13, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$b2ae07e7-6655-4f4e-804a-16d93d507a24$tag$, $tag$2026011900021$tag$, $tag$Bruna ferreira (5598984209077)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia!","time":"19/01/2026 08:07:46"},{"role":"client","text":"🌟 Bom dia Bruna ferreira! Que alegria ter você aqui com a gente! 🙌","time":"19/01/2026 08:07:47"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"19/01/2026 08:07:51"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"19/01/2026 08:07:56"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"19/01/2026 08:08:03"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"19/01/2026 08:08:53"},{"role":"client","text":"Olá! Bruna ferreira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"19/01/2026 08:08:54"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"19/01/2026 08:08:58"},{"role":"client","text":"Falar com um atendente","time":"19/01/2026 08:09:09"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"19/01/2026 08:09:10"},{"role":"client","text":"Pós graduação educação clássica","time":"19/01/2026 08:09:29"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/01/2026 09:13:36"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"19/01/2026 09:15:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"19/01/2026 09:15:51","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"19/01/2026 09:15:59","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Olá Karina! Td bem?","time":"19/01/2026 09:16:17"},{"role":"client","text":"Gostaria de saber se está tudo certo com a minha vaga pra iniciar a pós em abril","time":"19/01/2026 09:17:01"},{"role":"client","text":"Tirar umas dúvidas e falar sobre umas amigas que querem fazer o curso tb","time":"19/01/2026 09:18:23"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"19/01/2026 09:37:19","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* A senhora já fez inscrição correto?","time":"19/01/2026 09:37:36","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Já sim. Numa promoção de 70% com uma galera (Angelita)","time":"19/01/2026 09:38:16"},{"role":"client","text":"Queria saber se tá tudo certinho, se mandei tudo ou ta faltando algo?","time":"19/01/2026 09:38:44"},{"role":"client","text":"Quando fiz, gerou um boleto pra eu pagar, mas era só ignorar ele né? Pq um dia desses ainda tava me cobrando que não tinha sido pago, esses avisos de banco de boleto, sabe?","time":"19/01/2026 09:39:44"},{"role":"client","text":"Daí no caso estando tudo certo, já paguei a primeira e vai ficar faltando 15 parcelas, isso?","time":"19/01/2026 09:40:16"},{"role":"agent","text":"*Karina Pimentel:* Qual seu nome completo por gentileza?","time":"19/01/2026 10:26:19","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bruna van der laan Ferreira","time":"19/01/2026 10:32:11"},{"role":"agent","text":"*Karina Pimentel:* Está tudo certo sim, próxima fatura somente em Abril, no mês de inicio do curso!","time":"19/01/2026 10:41:15","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Certo","time":"19/01/2026 10:47:25"},{"role":"client","text":"Daí agora faltam 15 parcelas, isso?","time":"19/01/2026 10:47:34"},{"role":"client","text":"Outra coisa. Estava comentando com algumas amigas sobre a pós q vou começar, e falei q aproveitei esse desconto de 70%. As 3 amigas queriam se juntar pra adquirir tb nesse desconto pra começar agora em abril. Elas ainda conseguiriam?","time":"19/01/2026 10:48:34"},{"role":"client","text":"No caso elas queriam fazer essa mesma pós que vou fazer.","time":"19/01/2026 10:49:31"},{"role":"agent","text":"*Karina Pimentel:* Isso mesmo!","time":"19/01/2026 10:53:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Promoção da Black se encerrou, hoje teremos 50% de desconto!","time":"19/01/2026 10:53:50","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Então elas conseguiriam 50%?","time":"19/01/2026 10:54:12"},{"role":"client","text":"Qual o valor que fica por favor, pra eu passar pra elas","time":"19/01/2026 10:54:27"},{"role":"client","text":"Cada uma faz a inscrição  individual ou tem q ser grupo de 3 de novo?","time":"19/01/2026 10:54:52"},{"role":"agent","text":"*Karina Pimentel:* Isso, será mensais de R$ 239,58.","time":"19/01/2026 10:54:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Vou passar pra elas. Tem q se juntar em grupo ou cada uma pode fazer a sua?","time":"19/01/2026 10:55:41"},{"role":"agent","text":"*Karina Pimentel:* Não precisa do grupo não, seria o valor para cada!","time":"19/01/2026 10:56:31","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* \n  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"19/01/2026 11:55:27","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Legal!","time":"19/01/2026 11:55:45"},{"role":"client","text":"Vou passar pra elas a informação. Se elas quiserem se inscrever com esse valor, dá pra inscrever por qual link?","time":"19/01/2026 11:56:13"},{"role":"agent","text":"*Karina Pimentel:* Vou deixar aqui o link ok!","time":"19/01/2026 11:59:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* \n \n 🎁 Cupom de Desconto ECC: *BOLSA50*\n\n📌 Realize sua matrícula no link: bit.ly/InscricaoPosECC2024\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"19/01/2026 12:00:24","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"19/01/2026 20:36:00","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nBruna ferreira, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/01/2026 20:36:03"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"19/01/2026 20:36:04"},{"role":"client","text":"Bruna ferreira, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"19/01/2026 20:51:05"}]$tag$, $tag$2026-01-19 08:07:46+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 15, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
