INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$0b4f0b83-9175-4eef-9354-2afc12488fd9$tag$, $tag$2026011900066$tag$, $tag$Maria Eduarda. (5521967467050)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá! Bom dia.","time":"19/01/2026 10:45:06"},{"role":"client","text":"🌟 Bom dia Maria Eduarda.! Que alegria ter você aqui com a gente! 🙌","time":"19/01/2026 10:45:08"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"19/01/2026 10:45:12"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"19/01/2026 10:45:17"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"19/01/2026 10:45:21"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"19/01/2026 10:45:27"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"19/01/2026 10:45:33"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"19/01/2026 10:45:34"},{"role":"client","text":"A matrícula só é feita por esses três ?","time":"19/01/2026 10:45:50"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.","time":"19/01/2026 10:45:51"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"19/01/2026 10:45:52"},{"role":"client","text":"Sim, concordo","time":"19/01/2026 10:46:06"},{"role":"client","text":"✅ Obrigado, Maria Eduarda.! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"19/01/2026 10:46:08"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"19/01/2026 10:46:12"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"19/01/2026 10:46:54"},{"role":"client","text":"Olá! Maria Eduarda.!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"19/01/2026 10:46:55"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"19/01/2026 10:46:59"},{"role":"client","text":"Falar com um atendente","time":"19/01/2026 10:47:13"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"19/01/2026 10:47:13"},{"role":"client","text":"Teologia.","time":"19/01/2026 10:47:28"},{"role":"client","text":"Matrícula da faculdade de teologia EAD.","time":"19/01/2026 11:30:45"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/01/2026 13:19:18"},{"role":"agent","text":"*Karina Pimentel:*  A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"19/01/2026 13:20:06","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/01/2026 13:21:06","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Quero fazer minha matrícula.","time":"19/01/2026 14:02:28"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"19/01/2026 15:22:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar as formas de ingresso! ","time":"19/01/2026 15:22:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"19/01/2026 15:22:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"19/01/2026 20:42:47","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nMaria Eduarda., esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/01/2026 20:42:49"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"19/01/2026 20:42:50"},{"role":"client","text":"Maria Eduarda., Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"19/01/2026 20:57:51"}]$tag$, $tag$2026-01-19 10:45:06+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$b0133438-59a7-45dc-959c-d1172a531e1a$tag$, $tag$2026011900067$tag$, $tag$Emanuel Monteiro (5583981876305)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"19/01/2026 10:49:29"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"19/01/2026 10:49:30"},{"role":"client","text":"Ok","time":"19/01/2026 10:56:35"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/01/2026 10:57:17"},{"role":"agent","text":"*Karina Pimentel:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"19/01/2026 10:58:00","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/01/2026 10:58:25","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Terminei o 6° período na uniesp","time":"19/01/2026 11:04:19"},{"role":"client","text":"Gostaria de saber","time":"19/01/2026 11:04:27"},{"role":"client","text":"Qual o valor da mensalidade","time":"19/01/2026 11:04:35"},{"role":"agent","text":"*Karina Pimentel:* Perdão, enviei errado acima!","time":"19/01/2026 11:06:38","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"19/01/2026 11:07:02","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Quando voltam as aulas?","time":"19/01/2026 11:07:42"},{"role":"agent","text":"*Karina Pimentel:* 06/02","time":"19/01/2026 11:08:43","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"O que eu preciso fazer","time":"19/01/2026 11:21:11"},{"role":"client","text":"Para a transferência","time":"19/01/2026 11:21:14"},{"role":"client","text":"Preciso ir na uniesp?","time":"19/01/2026 11:21:18"},{"role":"client","text":"Ou ir direto pra cidade viva?","time":"19/01/2026 11:21:28"},{"role":"agent","text":"*Karina Pimentel:* Em caso de transferência será necessário preencher um formulário, para ser analisado as disciplinas!","time":"19/01/2026 11:22:15","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( *https://bit.ly/Aproveitamento-FICV* ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"19/01/2026 11:22:42","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"19/01/2026 20:34:04","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nEmanuel Monteiro, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"19/01/2026 20:34:07"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"22/01/2026 11:19:31"},{"role":"client","text":"Sua sessão expirou!","time":"22/01/2026 11:21:32"}]$tag$, $tag$2026-01-19 10:49:29+00$tag$, FALSE, FALSE, 7.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 10, 2, 9, 8, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
