INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$780b0ff4-ab22-4702-94aa-9aabe65d8e22$tag$, $tag$2026011900138$tag$, $tag$Eloísa (5584991247632)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá, boa tarde!","time":"19/01/2026 14:41:07"},{"role":"client","text":"🌟 Boa tarde Eloísa! Que alegria ter você aqui com a gente! 🙌","time":"19/01/2026 14:41:08"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"19/01/2026 14:41:12"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"19/01/2026 14:41:16"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"19/01/2026 14:41:21"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"19/01/2026 14:41:27"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"19/01/2026 14:41:33"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"19/01/2026 14:41:34"},{"role":"client","text":"Sim, concordo","time":"19/01/2026 14:42:19"},{"role":"client","text":"✅ Obrigado, Eloísa! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"19/01/2026 14:42:20"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"19/01/2026 14:42:24"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"19/01/2026 14:42:40"},{"role":"client","text":"Olá! Eloísa!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"19/01/2026 14:42:42"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"19/01/2026 14:42:45"},{"role":"client","text":"Saber sobre os cursos","time":"19/01/2026 14:43:10"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"19/01/2026 14:43:14"},{"role":"client","text":"Graduação","time":"19/01/2026 14:43:28"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"19/01/2026 14:43:32"},{"role":"client","text":"Teologia (EAD)","time":"19/01/2026 14:43:44"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"19/01/2026 14:43:45"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"19/01/2026 14:43:50"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"19/01/2026 14:44:15"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"19/01/2026 14:44:16"},{"role":"client","text":"ok, no aguardo","time":"19/01/2026 14:44:39"},{"role":"client","text":"Eu pretendo realizar minha matricula na graduação em teologia EAD com minha nota do enem. Gostaria de tirar algumas duvidas.","time":"19/01/2026 14:47:00"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/01/2026 14:50:47"},{"role":"agent","text":"*Karina Pimentel:*  A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"19/01/2026 14:51:33","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/01/2026 14:51:56","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Usando a nota do enem tem alguma bolsa de desconto?","time":"19/01/2026 16:11:49"},{"role":"agent","text":"*Karina Pimentel:* Boa noite!","time":"19/01/2026 20:49:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* O valor seria o mesmo!","time":"19/01/2026 20:49:45","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar um requerimento de desconto ok!\n","time":"19/01/2026 20:50:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  https://bit.ly/RequerimentodeDescontoFICV","time":"19/01/2026 20:50:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"20/01/2026 08:44:51","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nEloísa, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/01/2026 08:44:52"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/01/2026 08:44:53"},{"role":"client","text":"Eloísa, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em con