INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$cd20ec07-6fe1-4b75-a8dc-d762347e0f04$tag$, $tag$2026011900171$tag$, $tag$Mercinha (5583996703191)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Qual o valor da rematrícula Teologia EAD ?","time":"19/01/2026 16:35:13"},{"role":"client","text":"🌟 Boa tarde Mercinha! Que alegria ter você aqui com a gente! 🙌","time":"19/01/2026 16:35:14"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"19/01/2026 16:35:19"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"19/01/2026 16:35:23"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"19/01/2026 16:35:27"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"19/01/2026 16:35:34"},{"role":"client","text":"Estou fora de João Pessoa","time":"19/01/2026 16:35:37"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"19/01/2026 16:35:38"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"19/01/2026 16:35:39"},{"role":"client","text":"Sim, concordo","time":"19/01/2026 16:36:02"},{"role":"client","text":"✅ Obrigado, Mercinha! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"19/01/2026 16:36:02"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"19/01/2026 16:36:07"},{"role":"client","text":"Teologia EAD","time":"19/01/2026 16:38:49"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"19/01/2026 16:38:50"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"19/01/2026 16:38:51"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"19/01/2026 16:47:01"},{"role":"client","text":"Olá! Mercinha!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"19/01/2026 16:47:02"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"19/01/2026 16:47:07"},{"role":"client","text":"Falar com um atendente","time":"19/01/2026 16:47:32"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"19/01/2026 16:47:33"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/01/2026 20:22:03"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"19/01/2026 20:22:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"19/01/2026 20:23:01","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"20/01/2026 08:17:01","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nMercinha, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/01/2026 08:17:03"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/01/2026 08:17:04"},{"role":"client","text":"Mercinha, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/01/2026 08:32:05"}]$tag$, $tag$2026-01-19 16:35:13+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$00ac0afb-ad0c-44cd-8d46-9731378abe74$tag$, $tag$2026011900175$tag$, $tag$Daniele Ribeiro (5583999547074)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá","time":"19/01/2026 16:44:08"},{"role":"client","text":"🌟 Boa tarde Daniele Ribeiro! Que alegria ter você aqui com a gente! 🙌","time":"19/01/2026 16:44:09"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"19/01/2026 16:44:13"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"19/01/2026 16:44:17"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"19/01/2026 16:44:21"},{"role":"client","text":"Gostaria de informações a respeito do curso presencial de direito","time":"19/01/2026 16:44:25"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"19/01/2026 16:44:26"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"19/01/2026 16:44:31"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"19/01/2026 16:44:32"},{"role":"client","text":"Sim, concordo","time":"19/01/2026 16:44:50"},{"role":"client","text":"✅ Obrigado, Daniele Ribeiro! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"19/01/2026 16:44:51"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"19/01/2026 16:44:55"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"19/01/2026 16:45:10"},{"role":"client","text":"Olá! Daniele Ribeiro!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"19/01/2026 16:45:12"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"19/01/2026 16:45:16"},{"role":"client","text":"Saber sobre os cursos","time":"19/01/2026 16:45:30"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"19/01/2026 16:45:35"},{"role":"client","text":"Graduação","time":"19/01/2026 16:45:45"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"19/01/2026 16:45:50"},{"role":"client","text":"Direito (Presencial)","time":"19/01/2026 16:46:03"},{"role":"client","text":"Excelente escolha! O curso de Direito da FICV é presencial em João Pessoa, tem nota máxima no MEC, prática jurídica desde o primeiro período e bolsa de 60% em todas as mensalidades!\n","time":"19/01/2026 16:46:04"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"19/01/2026 16:46:08"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"19/01/2026 16:46:28"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"19/01/2026 16:46:28"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/01/2026 20:21:05"},{"role":"agent","text":"*Karina Pimentel:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"19/01/2026 20:21:33","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"19/01/2026 20:21:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"O desconto é só mediante o pagamento do semestre todo ?","time":"19/01/2026 20:24:28"},{"role":"agent","text":"*Karina Pimentel:* Não. Pode pagar mensalmente e desconto será mantido! Realizando os pagamentos até o dia 10 de todo mês será mantido!","time":"19/01/2026 20:57:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Precisa da nota do ENEM","time":"19/01/2026 20:57:40"},{"role":"client","text":"ou não precisa pra obter esse desconto?","time":"19/01/2026 20:57:51"},{"role":"agent","text":"*Karina Pimentel:* O ENEM não vai interferir no valor, seria somente a forma de se ingressar!","time":"19/01/2026 21:02:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"19/01/2026 21:02:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"20/01/2026 08:45:51","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nDaniele Ribeiro, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/01/2026 08:45:56"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/01/2026 08:45:57"},{"role":"client","text":"Daniele Ribeiro, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/01/2026 09:00:58"}]$tag$, $tag$2026-01-19 16:44:08+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$e20626ce-0d48-4d43-9938-75c66d8ae90c$tag$, $tag$2026010100002$tag$, $tag$Gabriela (5581995485209)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Educacao Crista Classica e quero mais informações.","time":"01/01/2026 09:15:17"},{"role":"client","text":"🌟 Bom dia Gabriela! Que alegria ter você aqui com a gente! 🙌","time":"01/01/2026 09:15:18"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"01/01/2026 09:15:22"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"01/01/2026 09:15:25"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"01/01/2026 09:15:29"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"01/01/2026 09:15:35"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"01/01/2026 09:15:41"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"01/01/2026 09:15:42"},{"role":"client","text":"Sim, concordo","time":"01/01/2026 09:15:54"},{"role":"client","text":"✅ Obrigado, Gabriela! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"01/01/2026 09:15:55"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"01/01/2026 09:15:58"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"01/01/2026 09:16:12"},{"role":"client","text":"Olá! Gabriela!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"01/01/2026 09:16:13"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"01/01/2026 09:16:16"},{"role":"client","text":"Saber sobre os cursos","time":"01/01/2026 09:16:29"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"01/01/2026 09:16:32"},{"role":"client","text":"Pós-Graduação","time":"01/01/2026 09:16:41"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"01/01/2026 09:16:45"},{"role":"client","text":"Educação Cristã Clássica","time":"01/01/2026 09:17:02"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"01/01/2026 09:17:03"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"01/01/2026 09:17:06"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"01/01/2026 09:17:17"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"01/01/2026 09:17:18"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"01/01/2026 09:17:19"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 07:52:58"},{"role":"client","text":"Bom dia","time":"02/01/2026 07:55:17"},{"role":"client","text":"Gostaria de mais informações sobre a pós graduação em Educação clássica","time":"02/01/2026 07:55:43"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n","time":"02/01/2026 07:56:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"02/01/2026 07:56:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"02/01/2026 07:57:03","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não existe outra maneira de conseguir mais um desconto sobre esse valor de mensalidade?","time":"02/01/2026 08:01:11"},{"role":"client","text":"Como posso me inscrever?","time":"02/01/2026 08:02:35"},{"role":"client","text":"Nossa igreja é parte do campus da Cidade Viva","time":"02/01/2026 08:03:55"},{"role":"client","text":"É a igreja Rio, no Recife","time":"02/01/2026 08:04:03"},{"role":"client","text":"Será que através disso posso conseguir mais algum desconto ou algo assim?","time":"02/01/2026 08:04:53"},{"role":"agent","text":"*Karina Pimentel:* Conseguimos sim!","time":"02/01/2026 08:07:30","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 50% de desconto!","time":"02/01/2026 08:07:38","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Mensalidades ficarão no valor de R$ 239,58.","time":"02/01/2026 08:08:04","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Obaaaa","time":"02/01/2026 08:08:06"},{"role":"client","text":"Benção!!!!!","time":"02/01/2026 08:08:24"},{"role":"client","text":"Do que preciso?","time":"02/01/2026 08:08:39"},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar o link ok!","time":"02/01/2026 08:33:40","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* 🎁 Cupom de Desconto ECC: *BOLSA50*\n\n📌 Realize sua matrícula no link: bit.ly/InscricaoPosECC2024\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"02/01/2026 08:34:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"02/01/2026 15:52:56","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deu certo a sua inscrição, Sra Gabriela?","time":"02/01/2026 15:53:14","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:*  Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"02/01/2026 17:53:44","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nGabriela, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 17:53:46"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"02/01/2026 17:53:47"},{"role":"client","text":"Gabriela, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"02/01/2026 18:08:47"}]$tag$, $tag$2026-01-01 09:15:17+00$tag$, FALSE, TRUE, 9, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 6, 9, 11, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$d5b38fe4-4bdd-48c9-852f-7eaf89dd1487$tag$, $tag$2026010100004$tag$, $tag$Sandra Gorete (5582987813146)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"01/01/2026 09:41:45"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"01/01/2026 09:41:46"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"01/01/2026 09:41:47"},{"role":"client","text":"Amém","time":"01/01/2026 18:20:36"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 07:53:01"},{"role":"client","text":"Bom dia a paz","time":"02/01/2026 08:59:57"},{"role":"agent","text":"*Karina Pimentel:* \n  A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"02/01/2026 09:03:22","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"02/01/2026 09:03:56","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"02/01/2026 15:53:20","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nSandra Gorete, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 15:53:23"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"05/01/2026 08:57:59"},{"role":"client","text":"Sua sessão expirou!","time":"05/01/2026 09:00:00"}]$tag$, $tag$2026-01-01 09:41:45+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$80bfc862-0683-470b-b875-f221a330f145$tag$, $tag$2026011900182$tag$, $tag$Polo Nova Iguaçu (5521995559919)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá.  Paz e Bem!\nJá preenchi meus dados na página Teologia Sistematica e gostaria de receber mais informações, por gentileza.","time":"19/01/2026 17:32:15"},{"role":"client","text":"🌟 Boa tarde Polo Nova Iguaçu! Que alegria ter você aqui com a gente! 🙌","time":"19/01/2026 17:32:16"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"19/01/2026 17:32:20"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"19/01/2026 17:32:23"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"19/01/2026 17:32:28"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"19/01/2026 17:32:34"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"19/01/2026 17:32:40"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"19/01/2026 17:32:41"},{"role":"client","text":"Sim, concordo","time":"19/01/2026 17:33:15"},{"role":"client","text":"✅ Obrigado, Polo Nova Iguaçu! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"19/01/2026 17:33:16"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"19/01/2026 17:33:20"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"19/01/2026 17:36:36"},{"role":"client","text":"Olá! Polo Nova Iguaçu!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"19/01/2026 17:36:37"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"19/01/2026 17:36:41"},{"role":"client","text":"Saber sobre os cursos","time":"19/01/2026 17:37:19"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"19/01/2026 17:37:23"},{"role":"client","text":"Pós-Graduação","time":"19/01/2026 17:37:41"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"19/01/2026 17:37:44"},{"role":"client","text":"Teologia Sistemática","time":"19/01/2026 17:38:49"},{"role":"client","text":"Aprofunde-se na fé cristã com uma base teológica sólida e estruturada.\n 📚 Estudos em Doutrina de Deus, Cristologia, Soteriologia, Pneumatologia e mais\n 📌 Voltado para teólogos, pastores e educadores\n 🎓 Professores mestres e doutores na área\n","time":"19/01/2026 17:38:50"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"19/01/2026 17:38:53"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"19/01/2026 17:39:20"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"19/01/2026 17:39:21"},{"role":"client","text":"Muito obrigado.","time":"19/01/2026 17:39:43"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"19/01/2026 19:51:32"},{"role":"agent","text":"*Karina Pimentel:* *Pós-Graduação em Teologia Sistemática* \n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"19/01/2026 19:52:16","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Teologia Sistemática está em 16 mensalidades de *R$ 359,37.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril.","time":"19/01/2026 19:53:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 287,50.\nVamos garantir a sua vaga? 😊","time":"19/01/2026 19:53:51","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Boa noite, Karina!\nQual é o investimento, por gentileza?","time":"19/01/2026 19:54:41"},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 287,50.\nVamos garantir a sua vaga? 😊\n","time":"19/01/2026 20:52:40","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bom dia!\nMuito obrigado pelo retorno, mas, esse valor está muito alto para o meu orçamento.","time":"20/01/2026 08:03:36"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"20/01/2026 08:52:29","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Trago lhe uma oferta imperdível! 😊","time":"20/01/2026 08:52:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 70% de desconto, fechando ainda hoje, mensais de R$ 107,81.","time":"20/01/2026 08:53:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"20/01/2026 10:46:27","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nPolo Nova Iguaçu, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/01/2026 10:46:31"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/01/2026 10:46:32"},{"role":"client","text":"5","time":"20/01/2026 10:59:19"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"20/01/2026 10:59:20"},{"role":"client","text":"2","time":"20/01/2026 10:59:46"},{"role":"client","text":"Polo Nova Iguaçu, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"20/01/2026 10:59:47"}]$tag$, $tag$2026-01-19 17:32:15+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 8, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
