INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$10b81a09-9f2f-4559-a952-a0ca5cb8f14c$tag$, $tag$2026012000043$tag$, $tag$Sergio (5583987684688)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"20/01/2026 09:24:24"},{"role":"client","text":"🌟 Bom dia Sergio! Que alegria ter você aqui com a gente! 🙌","time":"20/01/2026 09:24:25"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/01/2026 09:24:30"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/01/2026 09:24:34"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"20/01/2026 09:24:38"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"20/01/2026 09:24:44"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"20/01/2026 09:24:50"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"20/01/2026 09:24:51"},{"role":"client","text":"Sim, concordo","time":"20/01/2026 09:25:02"},{"role":"client","text":"✅ Obrigado, Sergio! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"20/01/2026 09:25:03"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/01/2026 09:25:07"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/01/2026 09:25:31"},{"role":"client","text":"Olá! Sergio!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/01/2026 09:25:32"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/01/2026 09:25:36"},{"role":"client","text":"Saber sobre os cursos","time":"20/01/2026 09:25:57"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"20/01/2026 09:26:01"},{"role":"client","text":"Graduação","time":"20/01/2026 09:26:31"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"20/01/2026 09:26:35"},{"role":"client","text":"Teologia (Presencial)","time":"20/01/2026 09:26:55"},{"role":"client","text":"✨ Você escolheu a modalidade presencial em João Pessoa!\nEssa é uma graduação com estrutura moderna, ensino prático desde o início e visão teológica fundamentada nas Escrituras, na tradição dos apóstolos e dos Pais da Igreja.\n\n\n 🎓 Curso reconhecido pelo MEC\n 🔠 Ensino de Grego e Hebraico\n 📌 Prática eclesiástica e liderança desde o início\n 🪙 Matrículas abertas com vagas promocionais!\n","time":"20/01/2026 09:26:55"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"20/01/2026 09:26:59"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"20/01/2026 09:27:23"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"20/01/2026 09:27:23"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/01/2026 09:38:14"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"20/01/2026 09:38:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 20%* na pontualidade durante toda graduação, que fica apenas R$ 439,64.  *Usando o cupom de desconto: BOLSA20*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.637,88).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 439,64 = R$ 2.637,88\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 527,57 = R$ 2.637,88\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 659,47 = R$ 2.637,88\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"20/01/2026 09:39:16","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"20/01/2026 11:23:34","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nSergio, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"20/01/2026 14:34:42"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"20/01/2026 14:34:43"},{"role":"client","text":"Sergio, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"20/01/2026 14:49:44"}]$tag$, $tag$2026-01-20 09:24:24+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id 