INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4d50022c-6a61-48dd-8a4f-632547f29ffd$tag$, $tag$2026012000092$tag$, $tag$Leidiane Maria Bandeira Barbosa (5586999933388)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"20/01/2026 11:42:05"},{"role":"client","text":"🌟 Bom dia Leidiane Maria Bandeira Barbosa! Que alegria ter você aqui com a gente! 🙌","time":"20/01/2026 11:42:07"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/01/2026 11:42:11"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/01/2026 11:42:15"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"20/01/2026 11:42:19"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"20/01/2026 11:42:25"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"20/01/2026 11:42:31"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"20/01/2026 11:42:33"},{"role":"client","text":"Si