INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8234125a-8b3d-4629-a86d-141c8b87c14e$tag$, $tag$2026012000096$tag$, $tag$Eloísa (5584991247632)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá, bom dia! Gostaria de tirar mais algumas dúvidas","time":"20/01/2026 11:54:46"},{"role":"client","text":"🌟 Bom dia Eloísa! Que alegria ter você aqui com a gente! 🙌","time":"20/01/2026 11:54:47"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/01/2026 11:54:51"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/01/2026 11:54:54"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/01/2026 11:55:02"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/01/2026 11:55:27"},{"role":"client","text":"Olá! Eloísa!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/01/2026 11:55:29"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/01/2026 11:55:32"},{"role":"client","text":"Falar com um atendente","time":"20/01/2026 11:55:45"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"20/01/2026 11:55:45"},{"role":"client","text":"Gostaria de tirar algumas dúvidas sobre a graduação EAD em teologia","time":"20/01/2026 11:56:27"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/01/2026 12:08:03"},{"role":"agent","text":"*Karina Pimentel:*  A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"20/01/2026 12:08:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"20/01/2026 12:08:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Gostaria de saber se tem materiais obrigatórios que vai precisar comprar, se o valor muda ou permanece o mesmo até o fim do curso, e gostaria de vê a grade curricular","time":"20/01/2026 12:16:28"},{"ro