INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$87d94d60-ad47-41da-9234-658dc03f6dbe$tag$, $tag$2026012000151$tag$, $tag$Não identificado (1856956881627532)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá, boa tarde!","time":"20/01/2026 15:56:00"},{"role":"client","text":"Olá aguarde só um momento que em breve alguém da nossa equipe irá te responder.","time":"20/01/2026 15:56:01"},{"role":"client","text":"A graduação em  direito presencial é qual período do dia?","time":"20/01/2026 15:56:20"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/01/2026 16:02:44"},{"role":"agent","text":"Karina Pimentel: Bacharelado em Direito\n\nGRADUAÇÃO COM COSMOVISÃO CRISTÃ\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\nNOTA MÁXIMA NO MEC\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( bit.ly/3LlEgJS ) com duração de 5 anos. \n\nPRÁTICA JURÍDICA\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\nNÚCLEO\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\nVOCAÇÃO\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\nBIBLIOTECA DIGITAL\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\nAULAS PRESENCIAIS\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"20/01/2026 16:03:06","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Karina Pimentel:  A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"20/01/2026 16:03:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Certo","time":"20/01/2026 19:14:28"},{"role":"client","text":"Meu contato:","time":"20/01/2026 19:14:30"},{"role":"client","text":"83 99857-9634","time":"20/01/2026 19:14:39"},{"role":"client","text":"Certo","time":"20/01/2026 19:15:16"},{"role":"client","text":"Obrigada!","time":"20/01/2026 19:15:18"},{"role":"agent","text":"Karina Pimentel: Bom dia!","time":"21/01/2026 08:11:39","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"Karina Pimentel: Como podemos lhe ajudar?","time":"21/01/2026 08:11:44","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"agent","text":"Karina Pimentel:  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"21/01/2026 14:31:54","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\n, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"21/01/2026 18:06:46"},{"role":"client","text":"Obrigado por entrar em contato conosco!\n\nVolte sempre!","time":"21/01/2026 18:06:47"}]$tag$, $tag$2026-01-20 15:56:00+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 9, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1710ceb2-a9b3-455e-a88a-48d3cadb2a5b$tag$, $tag$2026012000187$tag$, $tag$💝Cristiane Cavalcante (5566992407317)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"20/01/2026 17:22:09"},{"role":"client","text":"🌟 Boa tarde 💝Cristiane Cavalcante! Que alegria ter você aqui com a gente! 🙌","time":"20/01/2026 17:22:10"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"20/01/2026 17:22:14"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"20/01/2026 17:22:18"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"20/01/2026 17:22:21"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"20/01/2026 17:22:28"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"20/01/2026 17:22:34"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"20/01/2026 17:22:35"},{"role":"client","text":"Sim, concordo","time":"20/01/2026 17:22:54"},{"role":"client","text":"✅ Obrigado, 💝Cristiane Cavalcante! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"20/01/2026 17:22:55"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"20/01/2026 17:22:59"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"20/01/2026 17:23:12"},{"role":"client","text":"Olá! 💝Cristiane Cavalcante!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"20/01/2026 17:23:13"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"20/01/2026 17:23:17"},{"role":"client","text":"Saber sobre os cursos","time":"20/01/2026 17:23:29"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"20/01/2026 17:23:33"},{"role":"client","text":"Graduação","time":"20/01/2026 17:23:48"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"20/01/2026 17:23:53"},{"role":"client","text":"Teologia (EAD)","time":"20/01/2026 17:24:06"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"20/01/2026 17:24:08"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"20/01/2026 17:24:12"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"20/01/2026 17:24:28"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"20/01/2026 17:24:29"},{"role":"client","text":"Ok","time":"20/01/2026 17:24:42"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"20/01/2026 17:39:47"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"20/01/2026 17:40:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"20/01/2026 17:40:25","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   Boa tarde! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"21/01/2026 14:29:29","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\n💝Cristiane Cavalcante, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"21/01/2026 18:06:37"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"21/01/2026 18:06:38"},{"role":"client","text":"💝Cristiane Cavalcante, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"21/01/2026 18:21:39"}]$tag$, $tag$2026-01-20 17:22:09+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conc