INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$27dc08ff-285c-4a21-b428-0ffd6763437b$tag$, $tag$2026012100062$tag$, $tag$BRUNO TYRONE SOUZA VIRGINIO CABRAL (5583988309866)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"21/01/2026 09:59:31","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia","time":"21/01/2026 10:21:52"},{"role":"agent","text":"*Thayanne Sales:* Olá, graça e paz! 🙏\n\nMe chamo Thayanne, sou do Setor de Relacionamento da Faculdade Internacional Cidade Viva, e é um prazer falar com você! 😊\n\nIdentificamos o seu interesse pelo nosso curso de Pós-Graduação em Teologia Sistemática  e eu estou aqui para lhe auxiliar e tirar todas as suas dúvidas.\n\nPodemos conversar agora?","time":"21/01/2026 10:22:56","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Me passe as informações do curso","time":"21/01/2026 10:58:20"},{"role":"agent","text":"*Thayanne Sales:*  *Pós-Graduação em Teologia Sistemática* \n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"21/01/2026 11:21:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* TEOLOGIA SISTEMÁTICA - DISCIPLINAS DO CURSO:\n\nFUNDAMENTOS DA TEOLOGIA SISTEMÁTICA\nTeoria do Método Teológico e Teologia Fundamental\nTeologia Pastoral e Missiológica \nHistória da Teologia Cristã \nPerspectivas Teológico-filosóficas na pós modernidade\n\nDESDOBRAMENTOS DA TEOLOGIA SISTEMÁTICA\nTeontologia e Trindade\nCristologia \nPneumatologia e Teologia Pentecostal\nBibliologia\nAntropologia Teológica e Hamartiologia\nSoteriologia \nEclesiologia\nEscatologia \n\nObs: Professores sujeitos a alterações. ","time":"21/01/2026 11:21:48","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Teologia Sistemática está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026.\n\n\n🎁 Cupom de Desconto Teologia Sistemática: *BOLSA50*\n\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_25\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"21/01/2026 11:21:53","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"onde consta a lista do corpo docente?","time":"21/01/2026 11:39:30"},{"role":"agent","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6970e573f205953c77042546)","time":"21/01/2026 11:40:51","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"22/01/2026 08:30:12","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nBRUNO TYRONE SOUZA VIRGINIO CABRAL, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"22/01/2026 13:33:43"}]$tag$, $tag$2026-01-21 09:59:31+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, u