INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$aaf15c35-f60a-400d-99bf-26846bbf948b$tag$, $tag$2026012100180$tag$, $tag$Samantha Oliveira (5541991154234)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"21/01/2026 17:34:27"},{"role":"client","text":"🌟 Boa tarde Samantha Oliveira! Que alegria ter você aqui com a gente! 🙌","time":"21/01/2026 17:34:28"},{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"21/01/2026 17:34:29"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"21/01/2026 17:34:30"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"21/01/2026 17:34:34"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"21/01/2026 17:34:38"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"21/01/2026 17:34:44"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"21/01/2026 17:34:50"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"21/01/2026 17:34:51"},{"role":"client","text":"Gostaria de informações sobre a pós em teologia e educação clássica cristã por favor","time":"21/01/2026 17:35:01"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.","time":"21/01/2026 17:35:02"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"21/01/2026 17:35:02"},{"role":"client","text":"Sim, concordo","time":"21/01/2026 17:35:23"},{"role":"client","text":"✅ Obrigado, Samantha Oliveira! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"21/01/2026 17:35:24"},{"role":"client","text":"Sim, concordo","time":"21/01/2026 17:35:24"},{"role":"client","text":"✅ Obrigado, Samantha Oliveira! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"21/01/2026 17:35:25"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"21/01/2026 17:35:28"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"21/01/2026 17:35:56"},{"role":"client","text":"Olá! Samantha Oliveira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"21/01/2026 17:35:57"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"21/01/2026 17:36:01"},{"role":"client","text":"Saber sobre os cursos","time":"21/01/2026 17:36:16"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"21/01/2026 17:36:20"},{"role":"client","text":"Pós-Graduação","time":"21/01/2026 17:36:35"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"21/01/2026 17:36:40"},{"role":"client","text":"Educação Cristã Clássica","time":"21/01/2026 17:36:54"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"21/01/2026 17:36:54"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"21/01/2026 17:36:59"},{"role":"client","text":"Gestão Escolar","time":"21/01/2026 17:37:18"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"21/01/2026 17:37:19"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"21/01/2026 17:37:23"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"21/01/2026 17:37:26"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"21/01/2026 17:37:26"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"21/01/2026 17:37:34"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"21/01/2026 17:41:18"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"21/01/2026 17:42:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Quero informações sobre","time":"21/01/2026 17:43:18"},{"role":"client","text":"Boa tarde","time":"21/01/2026 17:43:22"},{"role":"client","text":"Graduação teologia","time":"21/01/2026 17:43:27"},{"role":"client","text":"Pós em gestão escolar e educas clássica cristã","time":"21/01/2026 17:43:27"},{"role":"client","text":"Todos EAD","time":"21/01/2026 17:43:47"},{"role":"agent","text":"*Thayanne Sales:*  PÓS-GRADUAÇÃO EM GESTÃO ESCOLAR.\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nD