INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$a705ccd8-b482-4a7b-b1de-939ef0814436$tag$, $tag$2026012100036$tag$, $tag$Flavia Prates (5521982005698)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"21/01/2026 09:03:04"},{"role":"client","text":"🌟 Bom dia Flavia Prates! Que alegria ter você aqui com a gente! 🙌","time":"21/01/2026 09:03:06"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"21/01/2026 09:03:11"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"21/01/2026 09:03:15"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"21/01/2026 09:03:19"},{"role":"client","text":"Faculdade","time":"21/01/2026 09:03:20"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"21/01/2026 09:03:20"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"21/01/2026 09:03:25"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"21/01/2026 09:03:31"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"21/01/2026 09:03:32"},{"role":"client","text":"Sim, concordo","time":"21/01/2026 09:03:44"},{"role":"client","text":"✅ Obrigado, Flavia Prates! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"21/01/2026 09:03:45"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"21/01/2026 09:03:48"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"21/01/2026 09:04:03"},{"role":"client","text":"Olá! Flavia Prates!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"21/01/2026 09:04:05"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"21/01/2026 09:04:09"},{"role":"client","text":"Saber sobre os cursos","time":"21/01/2026 09:04:28"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"21/01/2026 09:04:32"},{"role":"client","text":"Pós-Graduação","time":"21/01/2026 09:04:42"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"21/01/2026 09:04:46"},{"role":"client","text":"Gestão Escolar","time":"21/01/2026 09:05:04"},{"role":"client","text":"Forme-se como um líder educacional com visão estratégica, conhecimento de legislação e práticas pedagógicas atuais.\n\n 📌 Ideal para gestores, coordenadores e professores\n 🌐 Curso 100% EAD — estude de onde estiver\n 🗓️ Início das aulas em agosto\n 🎁 Condições especiais para novas matrículas\n","time":"21/01/2026 09:05:05"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"21/01/2026 09:05:09"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"21/01/2026 09:05:28"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"21/01/2026 09:05:29"},{"role":"client","text":"Okay","time":"21/01/2026 09:05:49"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"21/01/2026 09:24:45"},{"role":"agent","text":"*Karina Pimentel:* PÓS-GRADUAÇÃO EM GESTÃO ESCOLAR.\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n480 horas + 2 disciplinas optativas\n\nDISCIPLINAS\nDisciplinas: 12 + 2 disciplinas optativas\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"21/01/2026 09:25:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Gestão Escolar será de: 16 mensalidades de R$ 479,16.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril!","time":"21/01/2026 09:26:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades!