INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$3e528472-1386-4a9c-b6a6-67b4857bab94$tag$, $tag$2026012100069$tag$, $tag$Pr Falconery (5591985359389)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Formacao Politica e quero mais informações.","time":"21/01/2026 10:08:47"},{"role":"client","text":"🌟 Bom dia Pr Falconery! Que alegria ter você aqui com a gente! 🙌","time":"21/01/2026 10:08:48"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"21/01/2026 10:08:53"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"21/01/2026 10:08:57"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"21/01/2026 10:09:01"},{"role":"client","text":"Bom dia","time":"21/01/2026 10:09:06"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"21/01/2026 10:09:07"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"21/01/2026 10:09:07"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"21/01/2026 10:09:13"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"21/01/2026 10:09:14"},{"role":"client","text":"Sim, concordo","time":"21/01/2026 10:10:05"},{"role":"client","text":"✅ Obrigado, Pr Falconery! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"21/01/2026 10:10:06"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"21/01/2026 10:10:10"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"21/01/2026 10:10:31"},{"role":"client","text":"Olá! Pr Falconery!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"21/01/2026 10:10:32"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"21/01/2026 10:10:36"},{"role":"client","text":"Saber sobre os cursos","time":"21/01/2026 10:10:50"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"21/01/2026 10:10:54"},{"role":"client","text":"Pós-Graduação","time":"21/01/2026 10:11:05"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"21/01/2026 10:11:10"},{"role":"client","text":"Ciência Política","time":"21/01/2026 10:11:42"},{"role":"client","text":"Quer compreender os fundamentos políticos a partir de uma cosmovisão cristã?\n 📘 Curso voltado para quem atua ou deseja atuar em política, gestão pública ou liderança institucional\n 📅 Início em agosto\n 💻 Estudo online e contextualizado\n","time":"21/01/2026 10:11:43"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"21/01/2026 10:11:46"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"21/01/2026 10:12:11"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"21/01/2026 10:12:12"},{"role":"client","text":"Ok","time":"21/01/2026 10:12:27"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"21/01/2026 10:16:48"},{"role":"agent","text":"*Karina Pimentel:*  *Pós-Graduação em Ciência Política e Atuação Pública*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\nNossa carga horária é de 480 h.\n\nDISCIPLINAS\nContamos com um total de 11 disciplinas.\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"21/01/2026 10:17:22","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Ciência Política está em 16 mensalidades de R$ *487,00*.  Estamos com condição especiais com 20% e as mensalidades estão saindo por R$ 389,60\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Março.","time":"21/01/2026 10:18:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"21/01/2026 14:36:34","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"21/01/2026 18:07:28","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nPr Falconery, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"21/01/2026 18:07:30"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"21/01/2026 18:07:32"},{"role":"client","text":"Pr Falconery, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"21/01/2026 18:22:33"}]$tag$, $tag$2026-01-21 10:08:47+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4c3b882b-b3aa-4f8c-9667-d1af4a98110a$tag$, $tag$2026012100071$tag$, $tag$Jennifer Kelly Marques da Rocha (5531975331788)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"21/01/2026 10:09:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia","time":"21/01/2026 10:22:09"},{"role":"agent","text":"*Thayanne Sales:* Olá, graça e paz! 🙏\n\nMe chamo Thayanne, sou do Setor de Relacionamento da Faculdade Internacional Cidade Viva, e é um prazer falar com você! 😊\n\nIdentificamos o seu interesse pelo nosso curso de Graduação em Teologia EAD  e eu estou aqui para lhe auxiliar e tirar todas as suas dúvidas.\n\n\nPodemos conversar agora?","time":"21/01/2026 10:23:06","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Graça e paz Thayanne, conversamos semana passada","time":"21/01/2026 10:25:33"},{"role":"client","text":"Eu ainda não me decidi se farei a pós graduação ou a graduação em teologia","time":"21/01/2026 10:25:49"},{"role":"client","text":"Hahaha","time":"21/01/2026 10:25:53"},{"role":"client","text":"Estou orando sobre","time":"21/01/2026 10:25:57"},{"role":"agent","text":"*Thayanne Sales:* Compreendo","time":"21/01/2026 10:26:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"21/01/2026 10:26:23","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não, obrigada","time":"21/01/2026 10:26:46"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo dia. ","time":"21/01/2026 10:27:15","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nJennifer Kelly Marques da Rocha, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"21/01/2026 10:27:24"}]$tag$, $tag$2026-01-21 10:09:46+00$tag$, FALSE, FALSE, 7.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 7, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$e6ba3df2-5b46-4bc9-8711-9697c8f64b40$tag$, $tag$2026012100076$tag$, $tag$Andrea (55479922330565)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"21/01/2026 10:14:25","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nAndrea, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"21/01/2026 10:19:32"}]$tag$, $tag$2026-01-21 10:14:25+00$tag$, FALSE, FALSE, 5.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 9, 3, 2, 7, 1, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion