INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$fa8f32b1-eb27-42ee-870a-2b86dfb90e42$tag$, $tag$2026010100008$tag$, $tag$Ronaldo Junior (5521971549039)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"01/01/2026 10:33:28"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"01/01/2026 10:33:29"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"01/01/2026 10:33:30"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 07:53:10"},{"role":"agent","text":"*Karina Pimentel:* \n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"02/01/2026 09:30:48","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"02/01/2026 09:31:07","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nRonaldo Junior, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 16:23:10"},{"role":"client","text":"Atendimento Finalizado!\n\nRonaldo Junior, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 16:32:32"}]$tag$, $tag$2026-01-01 10:33:28+00$tag$, FALSE, FALSE, 5.8, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 3, 2, 9, 2, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
