INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8c66321a-4da3-43e8-8a0a-f0c80acdfeff$tag$, $tag$2026012100088$tag$, $tag$KARLARF.ADV⚖️ FILHADOREI (5564992161296)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"21/01/2026 10:36:29"},{"role":"client","text":"🌟 Bom dia KARLARF.ADV⚖️ FILHADOREI! Que alegria ter você aqui com a gente! 🙌","time":"21/01/2026 10:36:30"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"21/01/2026 10:36:34"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"21/01/2026 10:36:38"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"21/01/2026 10:36:45"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"21/01/2026 10:36:56"},{"role":"client","text":"Olá! KARLARF.ADV⚖️ FILHADOREI!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"21/01/2026 10:36:57"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"21/01/2026 10:37:01"},{"role":"client","text":"Saber sobre os cursos","time":"21/01/2026 10:37:18"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"21/01/2026 10:37:22"},{"role":"client","text":"Pós-Graduação","time":"21/01/2026 10:37:37"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"21/01/2026 10:37:41"},{"role":"client","text":"Novo Testamento","time":"21/01/2026 10:38:25"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"21/01/2026 10:38:26"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"21/01/2026 10:38:30"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"21/01/2026 10:38:50"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"21/01/2026 10:38:51"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"21/01/2026 10:39:45"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"21/01/2026 10:39:57","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Oi","time":"21/01/2026 10:40:02"},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"21/01/2026 10:40:08","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok","time":"21/01/2026 10:40:12"},{"role":"agent","text":"*Thayanne Sales:*   *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\n﻿Teologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações. ","time":"21/01/2026 10:40:12","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026. \n\n🎁 Cupom de Desconto Novo Testamento: *BOLSA50*\n\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_23\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"21/01/2026 10:40:20","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"22/01/2026 08:29:22","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nKARLARF.ADV⚖️ FILHADOREI, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"22/01/2026 13:30:52"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"22/01/2026 13:30:54"},{"role":"client","text":"KARLARF.ADV⚖️ FILHADOREI, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"22/01/2026 13:45:54"}]$tag$, $tag$2026-01-21 10:36:29+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
